To create a Discord bot using Discord.js v14 with a single slash command called "ban", follow these steps:

1. First, you need to install Discord.js v14:
```bash
npm install discord.js@14
```
1. Create a new directory for your bot and navigate to it:
```bash
mkdir discord-bot
cd discord-bot
```
1. Initialize a new Node.js project and install the necessary dependencies:
```bash
npm init -y
npm install discord.js axios
```
1. Create a `bot.js` file in your project directory and add the following boilerplate code:
```javascript
const Discord = require('discord.js');
const client = new Discord.Client();

client.on('ready', () => {
  console.log(`Logged in as ${client.user.tag}!`);
});

client.login(process.env.DISCORD_BOT_TOKEN);
```
1. Create a `commands.js` file in your project directory and add the following code to define your slash command:
```javascript
const { SlashCommand } = require('discord.js');

const banCommand = new SlashCommand('ban', {
  description: 'Bans a user.',
  converter: text => {
    if (text === 'help') {
      return new Discord.MessageEmbed()
        .setDescription('**Help for ban command:**')
        .addField('**Usage:**', '`!ban [user]`', false)
        .addField('**Examples:**', '`!ban @user`', false);
    } else if (text === '') {
      return new Discord.MessageEmbed()
        .setDescription('**Missing argument:** `user`')
        .addField('**Usage:**', '`!ban [user]`', false)
        .addField('**Examples:**', '`!ban @user`', false);
    } else {
      return new Discord.MessageEmbed()
        .setDescription('You have banned the user!')
        .addField('**Usage:**', '`!ban [user]`', false)
        .addField('**Examples:**', '`!ban @user`', false);
    }
  },
  args: [
    {
      name: 'user',
      type: 'user',
      alias: 'u',
      description: 'The user to ban.',
    },
  ],
});

module.exports = banCommand;
```
1. Update your `index.js` file to include the bot and the slash command:
```javascript
const Discord = require('discord.js');
require('dotenv').config();
require('./commands.js');

const bot = new Discord.Client();

bot.on('ready', () => {
  console.log(`Logged in as ${bot.user.tag}!`);
});

bot.login(process.env.DISCORD_BOT_TOKEN);
```
1. Now you can test your bot by typing `!ban @example-user` in any text channel. Your bot will reply with a message that the user has been banned.

Remember to replace `process.env.DISCORD_BOT_TOKEN` with your bot's token from the Discord Developer Portal.

